class PesticideItem {
  final String name;
  final String nameHindi;
  final String image;
  final String description;
  final String descriptionHindi;
  final String targetPests;
  final String targetPestsHindi;
  final String howToUse;
  final String howToUseHindi;
  final String dosage;
  final String dosageHindi;
  final String safetyInterval;
  final String safetyIntervalHindi;
  final String precautions;
  final String precautionsHindi;

  PesticideItem({
    required this.name,
    required this.nameHindi,
    required this.image,
    this.description = '',
    this.descriptionHindi = '',
    this.targetPests = '',
    this.targetPestsHindi = '',
    this.howToUse = '',
    this.howToUseHindi = '',
    this.dosage = '',
    this.dosageHindi = '',
    this.safetyInterval = '',
    this.safetyIntervalHindi = '',
    this.precautions = '',
    this.precautionsHindi = '',
  });
}

